     1→import type { PoseLandmark } from '@/types/pose';
     2→import { POSE_LANDMARKS } from '@/types/pose';
     3→import type { ClothingCategory, ClothingTransform, ClothingQuad, ClothingAnchorPoints } from '@/types/clothing';
     4→
     5→const MIN_VISIBILITY = 0.5;
     6→const PADDING_FACTOR = 1.5; // 50% padding around clothing for better coverage
     7→const SIZE_MULTIPLIER = 1.3; // Additional scale multiplier to compensate for square crops
     8→
     9→interface PixelCoord {
    10→  x: number;
    11→  y: number;
    12→}
    13→
    14→/**
    15→ * Convert normalized landmark coordinates to pixel coordinates
    16→ */
    17→export function landmarkToPixel(
    18→  landmark: PoseLandmark,
    19→  canvasWidth: number,
    20→  canvasHeight: number
    21→): PixelCoord {
    22→  return {
    23→    x: landmark.x * canvasWidth,
    24→    y: landmark.y * canvasHeight,
    25→  };
    26→}
    27→
    28→/**
    29→ * Calculate distance between two pixel coordinates
    30→ */
    31→function distance(a: PixelCoord, b: PixelCoord): number {
    32→  return Math.hypot(b.x - a.x, b.y - a.y);
    33→}
    34→
    35→/**
    36→ * Get the landmark indices needed for a clothing category
    37→ */
    38→function getCategoryLandmarks(category: ClothingCategory): number[] {
    39→  switch (category) {
    40→    case 'tops':
    41→      return [
    42→        POSE_LANDMARKS.LEFT_SHOULDER,
    43→        POSE_LANDMARKS.RIGHT_SHOULDER,
    44→        POSE_LANDMARKS.LEFT_ELBOW,
    45→        POSE_LANDMARKS.RIGHT_ELBOW,
    46→        POSE_LANDMARKS.LEFT_HIP,
    47→        POSE_LANDMARKS.RIGHT_HIP,
    48→      ];
    49→    case 'bottoms':
    50→      return [
    51→        POSE_LANDMARKS.LEFT_HIP,
    52→        POSE_LANDMARKS.RIGHT_HIP,
    53→        POSE_LANDMARKS.LEFT_KNEE,
    54→        POSE_LANDMARKS.RIGHT_KNEE,
    55→        POSE_LANDMARKS.LEFT_ANKLE,
    56→        POSE_LANDMARKS.RIGHT_ANKLE,
    57→      ];
    58→  }
    59→}
    60→
    61→/**
    62→ * Check if all required landmarks for a category are visible
    63→ */
    64→export function areLandmarksVisible(
    65→  landmarks: PoseLandmark[],
    66→  category: ClothingCategory
    67→): boolean {
    68→  const requiredIndices = getCategoryLandmarks(category);
    69→  return requiredIndices.every((idx) => landmarks[idx]?.visibility >= MIN_VISIBILITY);
    70→}
    71→
    72→/**
    73→ * Calculate affine transform for tops (shirts, jackets, hoodies)
    74→ * Uses 6-point anchor: shoulders + elbows + hips
    75→ * Projects onto 4-corner rectangle: shoulders + hips
    76→ */
    77→function calculateTopTransform(
    78→  landmarks: PoseLandmark[],
    79→  canvasWidth: number,
    80→  canvasHeight: number
    81→): ClothingTransform | null {
    82→  // Check visibility of all required landmarks
    83→  if (!areLandmarksVisible(landmarks, 'tops')) {
    84→    return null;
    85→  }
    86→
    87→  // Get landmarks
    88→  const lShoulder = landmarks[POSE_LANDMARKS.LEFT_SHOULDER];
    89→  const rShoulder = landmarks[POSE_LANDMARKS.RIGHT_SHOULDER];
    90→  const lHip = landmarks[POSE_LANDMARKS.LEFT_HIP];
    91→  const rHip = landmarks[POSE_LANDMARKS.RIGHT_HIP];
    92→
    93→  // Convert to pixels
    94→  const tlPx = landmarkToPixel(lShoulder, canvasWidth, canvasHeight);
    95→  const trPx = landmarkToPixel(rShoulder, canvasWidth, canvasHeight);
    96→  const blPx = landmarkToPixel(lHip, canvasWidth, canvasHeight);
    97→  const brPx = landmarkToPixel(rHip, canvasWidth, canvasHeight);
    98→
    99→  // Calculate center point
   100→  const centerX = (tlPx.x + trPx.x + blPx.x + brPx.x) / 4;
   101→  const centerY = (tlPx.y + trPx.y + blPx.y + brPx.y) / 4;
   102→
   103→  // Calculate dimensions - use shoulder width as reference to maintain aspect ratio
   104→  const shoulderWidth = distance(tlPx, trPx);
   105→  const scale = shoulderWidth * PADDING_FACTOR * SIZE_MULTIPLIER;
   106→
   107→  // Both width and height use the same scale to maintain aspect ratio
   108→  const width = scale;
   109→  const height = scale;
   110→
   111→  // Calculate rotation from shoulder line
   112→  // Add PI to flip 180 degrees (clothing images are typically oriented top-down)
   113→  const rotation = Math.atan2(trPx.y - tlPx.y, trPx.x - tlPx.x) + Math.PI;
   114→
   115→  return {
   116→    centerX,
   117→    centerY,
   118→    width,
   119→    height,
   120→    rotation
   121→  };
   122→}
   123→
   124→/**
   125→ * Calculate affine transform for bottoms (pants, shorts, skirts)
   126→ * Uses 6-point anchor: hips + knees + ankles
   127→ * Projects onto 4-corner rectangle: hips + ankles
   128→ */
   129→function calculateBottomTransform(
   130→  landmarks: PoseLandmark[],
   131→  canvasWidth: number,
   132→  canvasHeight: number
   133→): ClothingTransform | null {
   134→  // Check visibility
   135→  if (!areLandmarksVisible(landmarks, 'bottoms')) {
   136→    return null;
   137→  }
   138→
   139→  // Get landmarks
   140→  const lHip = landmarks[POSE_LANDMARKS.LEFT_HIP];
   141→  const rHip = landmarks[POSE_LANDMARKS.RIGHT_HIP];
   142→  const lAnkle = landmarks[POSE_LANDMARKS.LEFT_ANKLE];
   143→  const rAnkle = landmarks[POSE_LANDMARKS.RIGHT_ANKLE];
   144→
   145→  // Convert to pixels
   146→  const tlPx = landmarkToPixel(lHip, canvasWidth, canvasHeight);
   147→  const trPx = landmarkToPixel(rHip, canvasWidth, canvasHeight);
   148→  const blPx = landmarkToPixel(lAnkle, canvasWidth, canvasHeight);
   149→  const brPx = landmarkToPixel(rAnkle, canvasWidth, canvasHeight);
   150→
   151→  // Calculate center
   152→  const centerX = (tlPx.x + trPx.x + blPx.x + brPx.x) / 4;
   153→  const centerY = (tlPx.y + trPx.y + blPx.y + brPx.y) / 4;
   154→
   155→  // Calculate dimensions - use hip width as reference to maintain aspect ratio
   156→  const hipWidth = distance(tlPx, trPx);
   157→  const scale = hipWidth * PADDING_FACTOR * SIZE_MULTIPLIER;
   158→
   159→  // Both width and height use the same scale to maintain aspect ratio
   160→  const width = scale;
   161→  const height = scale;
   162→
   163→  // Calculate rotation from hip line
   164→  // Add PI to flip 180 degrees (clothing images are typically oriented top-down)
   165→  const rotation = Math.atan2(trPx.y - tlPx.y, trPx.x - tlPx.x) + Math.PI;
   166→
   167→  return {
   168→    centerX,
   169→    centerY,
   170→    width,
   171→    height,
   172→    rotation
   173→  };
   174→}
   175→
   176→/**
   177→ * Calculate clothing transform for any category
   178→ */
   179→export function calculateClothingTransform(
   180→  landmarks: PoseLandmark[],
   181→  category: ClothingCategory,
   182→  canvasWidth: number,
   183→  canvasHeight: number
   184→): ClothingTransform | null {
   185→  switch (category) {
   186→    case 'tops':
   187→      return calculateTopTransform(landmarks, canvasWidth, canvasHeight);
   188→    case 'bottoms':
   189→      return calculateBottomTransform(landmarks, canvasWidth, canvasHeight);
   190→  }
   191→}
   192→
   193→/**
   194→ * Scale image dimensions to fit target while maintaining aspect ratio
   195→ */
   196→export function scaleToFit(
   197→  imageWidth: number,
   198→  imageHeight: number,
   199→  targetWidth: number,
   200→  targetHeight: number
   201→): { width: number; height: number } {
   202→  const imageAspect = imageWidth / imageHeight;
   203→  const targetAspect = targetWidth / targetHeight;
   204→
   205→  if (imageAspect > targetAspect) {
   206→    // Image is wider - fit to width
   207→    return {
   208→      width: targetWidth,
   209→      height: targetWidth / imageAspect,
   210→    };
   211→  } else {
   212→    // Image is taller - fit to height
   213→    return {
   214→      width: targetHeight * imageAspect,
   215→      height: targetHeight,
   216→    };
   217→  }
   218→}
   219→
   220→/**
   221→ * Get the 4 corner points for clothing quad mapping
   222→ * This maps clothing image corners directly to body landmarks
   223→ * If anchor points are provided, uses them for precise mapping
   224→ */
   225→export function getClothingQuad(
   226→  landmarks: PoseLandmark[],
   227→  category: ClothingCategory,
   228→  canvasWidth: number,
   229→  canvasHeight: number,
   230→  anchorPoints?: ClothingAnchorPoints
   231→): ClothingQuad | null {
   232→  // Check visibility
