   235→  }
   236→
   237→  // If anchor points provided and valid, use them for direct mapping
   238→  if (anchorPoints && anchorPoints.leftShoulder && anchorPoints.rightShoulder) {
   239→    console.log('Using detected anchor points for precise alignment');
   240→    return mapAnchorsToBody(landmarks, category, anchorPoints, canvasWidth, canvasHeight);
   241→  }
   242→
   243→  // Fallback to landmark-based quad (original behavior)
   244→  if (category === 'tops') {
   245→    const lShoulder = landmarks[POSE_LANDMARKS.LEFT_SHOULDER];
   246→    const rShoulder = landmarks[POSE_LANDMARKS.RIGHT_SHOULDER];
   247→    const lHip = landmarks[POSE_LANDMARKS.LEFT_HIP];
   248→    const rHip = landmarks[POSE_LANDMARKS.RIGHT_HIP];
   249→
